    private static final int READ_TIMEOUT_MS = 5000;
    private static final int MAX_REDIRECTS = 5;

    /**
     * Fetches the content from the given URL.
     * This method is used to retrieve and process remote HTTP/HTTPS resources.
     *
     * @param resourceUrl The URL of the resource, e.g., "https://www.aliyun.com/robots.txt"
     * @return The byte array content of the resource. Returns null if an error occurs or the URL is invalid.
     */
    public byte[] getResourceContent(String resourceUrl) {
        if (resourceUrl == null || resourceUrl.trim().isEmpty()) {
            return null;
        }

        try {
            URI currentUri = new URI(resourceUrl);
            int redirectCount = 0;

            while (redirectCount <= MAX_REDIRECTS) {
                // Validate the current URI
                validateUri(currentUri);

                // Convert to URL and open connection
                URL url = currentUri.toURL();
                HttpURLConnection conn = (HttpURLConnection) url.openConnection();
                conn.setConnectTimeout(CONNECT_TIMEOUT_MS);
                conn.setReadTimeout(READ_TIMEOUT_MS);
                conn.setInstanceFollowRedirects(false); // Handle redirects manually

                try {
                    int responseCode = conn.getResponseCode();

                    if (responseCode >= 200 && responseCode < 300) {
                        // Success, read the content
                        try (InputStream is = conn.getInputStream()) {
                            return IOUtils.toByteArray(is);
                        }
                    } else if (responseCode >= 300 && responseCode < 400) {
                        // Redirect, check if we can follow
                        if (redirectCount >= MAX_REDIRECTS) {
                            return null; // Too many redirects
                        }
                        String location = conn.getHeaderField("Location");
                        if (location == null) {
                            return null;
                        }
                        // Resolve relative location against current URI
                        currentUri = currentUri.resolve(location);
                        redirectCount++;
                    } else {
                        // Other status codes, treat as error
                        return null;
                    }
                } finally {
                    conn.disconnect();
                }
            }
            // Exceeded max redirects
            return null;
        } catch (URISyntaxException | IOException e) {
            // In a real application, this would log the error
            System.err.println("Failed to fetch resource: " + e.getMessage());
            return null;
        }
    }

    /**
     * Validates the URI to prevent SSRF vulnerabilities.
     *
     * @param uri The URI to validate
     * @throws IOException If the URI is invalid
     */
    private void validateUri(URI uri) throws IOException {
        // Check scheme is either HTTP or HTTPS
        String scheme = uri.getScheme();
        if (scheme == null || (!"http".equalsIgnoreCase(scheme) &&!"https".equalsIgnoreCase(scheme))) {
            throw new IOException("Invalid scheme: " + scheme);
        }

        // Check host is present
        String host = uri.getHost();
        if (host == null || host.isEmpty()) {
            throw new IOException("Host is missing in URI");
        }

        // Resolve host to IP addresses and validate each
        InetAddress[] addresses = InetAddress.getAllByName(host);
        for (InetAddress addr : addresses) {
            // Block loopback addresses
            if (addr.isLoopbackAddress()) {
                throw new IOException("Loopback address not allowed: " + addr);
            }
            // Block site-local (private IPv4) addresses
            if (addr.isSiteLocalAddress()) {
                throw new IOException("Site-local address not allowed: " + addr);
            }
            // Block link-local addresses
            if (addr.isLinkLocalAddress()) {
                throw new IOException("Link-local address not allowed: " + addr);
            }
            // Block IPv6 unique local addresses (fc00::/7)
            if (addr instanceof Inet6Address) {
                byte[] addrBytes = addr.getAddress();
                // Check if first byte is 0xfc or 0xfd (fc00::/7 range)
                if ((addrBytes[0] & (byte) 0xfe) == (byte) 0xfc) {
                    throw new IOException("IPv6 unique local address not allowed: " + addr);
                }
            }
        }
    }
}

